#[cfg(test)]
mod tests {
    use super::*;
    use crate::geometry::evaluate_preset;

    #[test]
    fn test_all_original_11_shapes_are_registered() {
        let names = [
            "rect", "ellipse", "roundRect", "corner", "triangle",
            "notchedRightArrow", "leftCircularArrow", "circularArrow",
            "line", "arc", "straightConnector1",
        ];
        for name in names {
            assert!(lookup(name).is_some(), "Shape '{name}' not found in lookup");
        }
    }

    #[test]
    fn test_187_shapes_registered() {
        let names = [
            "accentBorderCallout1", "bentArrow", "chevron", "diamond", "ellipse",
            "flowChartProcess", "gear6", "heart", "irregularSeal1", "leftArrow",
            "mathPlus", "noSmoking", "octagon", "parallelogram", "rect",
            "roundRect", "star5", "trapezoid", "uturnArrow", "wave",
        ];
        for name in names {
            assert!(lookup(name).is_some(), "Shape '{name}' not found in lookup");
        }
    }

    #[test]
    fn test_rect_produces_4_lines_and_close() {
        let shape = evaluate_preset("rect", 100.0, 50.0, &[]).unwrap();
        assert_eq!(shape.paths.len(), 1);
        assert_eq!(shape.paths[0].commands.len(), 5);
    }

    #[test]
    fn test_ellipse_produces_arcs() {
        let shape = evaluate_preset("ellipse", 100.0, 80.0, &[]).unwrap();
        assert_eq!(shape.paths.len(), 1);
        assert!(shape.paths[0].commands.len() >= 6);
    }

    #[test]
    fn test_round_rect_has_arcs() {
        let shape = evaluate_preset("roundRect", 200.0, 100.0, &[]).unwrap();
        assert_eq!(shape.paths.len(), 1);
        assert!(shape.paths[0].commands.len() >= 9);
    }

    #[test]
    fn test_triangle_3_vertices() {
        let shape = evaluate_preset("triangle", 100.0, 80.0, &[]).unwrap();
        assert_eq!(shape.paths.len(), 1);
        assert_eq!(shape.paths[0].commands.len(), 4);
    }

    #[test]
    fn test_corner_l_shape() {
        let shape = evaluate_preset("corner", 100.0, 100.0, &[]).unwrap();
        assert_eq!(shape.paths.len(), 1);
        assert_eq!(shape.paths[0].commands.len(), 7);
    }

    #[test]
    fn test_notched_right_arrow() {
        let shape = evaluate_preset("notchedRightArrow", 200.0, 100.0, &[]).unwrap();
        assert_eq!(shape.paths.len(), 1);
        assert_eq!(shape.paths[0].commands.len(), 9);
    }

    #[test]
    fn test_line_has_two_commands() {
        let shape = evaluate_preset("line", 100.0, 50.0, &[]).unwrap();
        assert_eq!(shape.paths.len(), 1);
        assert_eq!(shape.paths[0].commands.len(), 2);
        assert!(shape.paths[0].stroke);
    }

    #[test]
    fn test_arc_has_two_paths() {
        let shape = evaluate_preset("arc", 100.0, 100.0, &[]).unwrap();
        assert_eq!(shape.paths.len(), 2);
        assert!(shape.paths[0].fill.is_filled());
        assert!(!shape.paths[0].stroke);
        assert!(!shape.paths[1].fill.is_filled());
        assert!(shape.paths[1].stroke);
    }

    #[test]
    fn test_circular_arrow_evaluates() {
        let shape = evaluate_preset("circularArrow", 200.0, 200.0, &[]).unwrap();
        assert_eq!(shape.paths.len(), 1);
        assert!(shape.paths[0].commands.len() >= 3);
    }

    #[test]
    fn test_left_circular_arrow_evaluates() {
        let shape = evaluate_preset("leftCircularArrow", 200.0, 200.0, &[]).unwrap();
        assert_eq!(shape.paths.len(), 1);
        assert!(shape.paths[0].commands.len() >= 3);
    }

    #[test]
    fn test_round_rect_custom_adjustment() {
        let shape = evaluate_preset("roundRect", 100.0, 50.0, &[("adj".into(), 0)]).unwrap();
        assert_eq!(shape.paths.len(), 1);
        assert!(shape.paths[0].commands.len() >= 5);
    }

    #[test]
    fn test_straight_connector1() {
        let shape = evaluate_preset("straightConnector1", 100.0, 50.0, &[]).unwrap();
        assert_eq!(shape.paths.len(), 1);
        assert_eq!(shape.paths[0].commands.len(), 2);
        assert!(!shape.paths[0].fill.is_filled());
    }

    #[test]
    fn test_text_rect_present() {
        for name in ["rect", "ellipse", "roundRect", "triangle", "corner", "notchedRightArrow"] {
            let shape = evaluate_preset(name, 100.0, 80.0, &[]).unwrap();
            assert!(shape.text_rect.is_some(), "Shape '{name}' should have a text rect");
        }
        let line = evaluate_preset("line", 100.0, 50.0, &[]).unwrap();
        assert!(line.text_rect.is_none());
    }
}

